const dados = $json;
let anexos = [];

// Converte a string de anexos de volta para Array, se necessário
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch (e) {
  anexos = [];
}

// LIMPEZA DO BASE64 (Remove o prefixo data:image/... caso o WhatsApp envie)
anexos = anexos.map(a => {
  let b64 = a.base64 || a.conteudo_base64 || '';
  if (b64.includes(',')) {
    b64 = b64.split(',')[1];
  }
  return { ...a, base64: b64 };
});

const tem_imagem = anexos.some(a => ['jpg','jpeg','png','webp','gif','bmp'].includes((a.tipo||'').toLowerCase()) && a.base64);
const tem_pdf    = anexos.some(a => (a.tipo||'').toLowerCase() === 'pdf');
const tem_excel  = anexos.some(a => ['xlsx','xls','csv'].includes((a.tipo||'').toLowerCase()));
const tem_audio  = anexos.some(a => ['ogg','mp3','wav','m4a','opus'].includes((a.tipo||'').toLowerCase()));

return { 
  json: { 
    ...dados, 
    anexos: anexos, 
    tipos_anexos: { tem_imagem, tem_pdf, tem_excel, tem_audio }, 
    precisa_preprocessamento: (tem_imagem || tem_pdf || tem_excel || tem_audio)
  } 
};

// O texto do PDF já vem do WF1 no campo 'texto_pdf'
const textoPdf = $json.texto_pdf || $json.text || $json.content || '';

return { json: { ...$('Tem PDF?').first().json, texto_pdf: textoPdf.substring(0, 8000) } };

const linhas = $items();
if (!linhas || linhas.length === 0) return { json: { ...$('Tem Excel?').first().json, texto_excel: '' } };
const cabecalhos = Object.keys(linhas[0].json);
let tabela = cabecalhos.join(' | ') + '\n' + cabecalhos.map(() => '---').join(' | ') + '\n';
linhas.forEach(item => { tabela += cabecalhos.map(c => String(item.json[c] ?? '')).join(' | ') + '\n'; });
return { json: { ...$('Tem Excel?').first().json, texto_excel: tabela.substring(0, 6000) } };

const original = $json.texto || '';
const ocr   = $json.texto_ocr || '';
const pdf   = $json.texto_pdf || '';
const excel = $json.texto_excel || '';
const audio = $json.texto_audio || '';

const partes = [
  original && `[MENSAGEM ORIGINAL]\n${original}`,
  ocr      && `[IMAGEM - TEXTO EXTRAÍDO POR OCR]\n${ocr}`,
  pdf      && `[PDF - TEXTO EXTRAÍDO]\n${pdf}`,
  excel    && `[EXCEL - CONTEÚDO DA TABELA]\n${excel}`,
  audio    && `[ÁUDIO - TRANSCRIÇÃO]\n${audio}`
].filter(Boolean);

return { 
  json: { 
    ...$json, 
    texto_enriquecido: partes.join('\n\n═══════════════════════\n\n')
  } 
};

// 1. Puxa os dados originais do nó antes do Agente de IA
const dadosOriginais = $('Montar Texto Enriquecido').first().json;

// 2. Pega na resposta da IA
const output = $json.output || $json.text || $json.content || '';

let c;
try { 
  c = JSON.parse(output.replace(/```json/gi,'').replace(/```/g,'').trim()); 
} catch(e) { 
  const m = output.match(/\{[\s\S]*?\}/); 
  c = m ? JSON.parse(m[0]) : { categoria: 'outros', confianca: 0, resumo: '' }; 
}

if (!['proforma','compra','outros'].includes(c.categoria)) c.categoria = 'outros';

// 3. Mescla os dados originais com a nova classificação
return { 
  json: { 
    ...dadosOriginais, 
    categoria: c.categoria, 
    confianca_classificacao: c.confianca || 0, 
    resumo_classificacao: c.resumo || '' 
  } 
};

// 1. Puxa os dados completos que entraram na rota de compra
const dadosOriginais = $('Switch por Categoria').first().json;

const output = $json.output || $json.text || $json.content || '';
let extraido;
try { 
  extraido = JSON.parse(output.replace(/```json/gi,'').replace(/```/g,'').trim()); 
} catch(e) { 
  const m = output.match(/\{[\s\S]*\}/); 
  extraido = m ? JSON.parse(m[0]) : { itens: [] }; 
}

let contador = 1;
const itensFinal = (extraido.itens || []).map(item => ({
  codigo:    (item.codigo && item.codigo.trim()) ? item.codigo.trim().toUpperCase() : ('ITEM' + String(contador++).padStart(3,'0')),
  descricao: (item.descricao || 'Item sem descrição').trim(),
  unidade:   (item.unidade || '').trim(),
  quantidade: Number(item.quantidade) || 1
}));

// 2. Adiciona os itens aos dados originais
dadosOriginais.pedido_id   = 'PED-' + new Date().toISOString().replace(/[-:T]/g,'').split('.')[0];
dadosOriginais.itens       = itensFinal;
dadosOriginais.total_itens = itensFinal.length;

return { json: dadosOriginais };

const dados = $json;
dados.margem_percentual = 0;
return { json: dados };

const p = $json;
const margem = p.margem_percentual || 0;
let prioridade, label;
if (margem >= 40)      { prioridade = 1; label = 'ALTA'; }
else if (margem >= 20) { prioridade = 2; label = 'MÉDIA'; }
else                   { prioridade = 3; label = 'BAIXA'; }
return { json: { ...p, prioridade, prioridade_label: label, sla_minutos: prioridade === 1 ? 30 : prioridade === 2 ? 60 : 120 } };

const axios = require('axios');

// 1. CONFIGURAÇÕES
const API_KEY = 'ppEa5Z2guZyMxcGo4y8L4eDr222Wyvdd';
const dados = $json;
let texto_acumulado = "";

// 2. EXTRAÇÃO E LIMPEZA
let anexos = [];
try {
  anexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
} catch (e) {
  anexos = [];
}

const imagens = anexos.filter(a =>
  ['jpg', 'jpeg', 'png', 'webp'].includes((a.tipo || '').toLowerCase()) && a.base64
);

if (imagens.length === 0) {
  return [{ json: { ...dados, texto_ocr: 'Nenhuma imagem encontrada' } }];
}

// 3. PROCESSAMENTO SEQUENCIAL
for (let i = 0; i < imagens.length; i++) {
  try {
    // Limpa o base64 e remove o prefixo se existir
    let b64 = imagens[i].base64.replace(/\s/g, '');
    if (b64.includes(',')) b64 = b64.split(',')[1];

    // Determina o mime type com base no campo "tipo"
    const tipo = (imagens[i].tipo || 'jpeg').toLowerCase();
    const mimeMap = { jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', webp: 'image/webp' };
    const mimeType = mimeMap[tipo] || 'image/jpeg';

    // ✅ FORMATO CORRETO: type "image_url" com data URI completo
    const response = await axios.post(
      'https://api.mistral.ai/v1/ocr',
      {
        model: "mistral-ocr-latest",
        document: {
          type: "image_url",
          image_url: `data:${mimeType};base64,${b64}`
        }
      },
      {
        headers: {
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json'
        },
        timeout: 60000,
        maxBodyLength: Infinity,   // necessário para payloads grandes
        maxContentLength: Infinity
      }
    );

    // Limpeza de memória imediata
    b64 = null;
    imagens[i].base64 = null;

    if (response.data && response.data.pages) {
      const markdown = response.data.pages.map(p => p.markdown).join('\n');
      texto_acumulado += (texto_acumulado ? '\n\n' : '') + markdown;
    }

  } catch (err) {
    // Log detalhado do erro para debug
    const status = err.response?.status || 'sem status';
    const msg = err.response?.data?.message || err.response?.data?.detail || err.message;
    texto_acumulado += `\n[Erro Imagem ${i+1} | Status ${status}: ${msg}]`;
  }

  // Pausa entre requests para não sobrecarregar a API
  if (i < imagens.length - 1) {
    await new Promise(r => setTimeout(r, 300));
  }
}

// 4. RETORNO LIMPO (sem base64 para não crashar o N8N)
const output = { ...dados };
delete output.anexos;
delete output.message_raw;
output.texto_ocr = texto_acumulado;

return [{ json: output }];

const axios = require('axios');
const XLSX = require('xlsx');

const API_KEY = 'ppEa5Z2guZyMxcGo4y8L4eDr222Wyvdd'; 
const dados = { ...$json };

// ─── 1. CAÇADOR DE BASE64 (Ignora URLs corrompidas) ────────────────
let b64Data = null;

// Tentativa A: Procura dentro do array "anexos"
try {
  let listaAnexos = typeof dados.anexos === 'string' ? JSON.parse(dados.anexos) : (dados.anexos || []);
  if (listaAnexos.length > 0 && listaAnexos[0].base64) {
    b64Data = listaAnexos[0].base64;
  }
} catch (e) {}

// Tentativa B: Procura direto na raiz do JSON
if (!b64Data && dados.base64) {
  b64Data = dados.base64;
}

// Tentativa C: Procura escondido dentro do message_raw (Comum na Evolution API)
if (!b64Data && dados.message_raw) {
  try {
    const parsed = typeof dados.message_raw === 'string' ? JSON.parse(dados.message_raw) : dados.message_raw;
    const msgStr = typeof parsed[0] === 'string' ? JSON.parse(parsed[0]) : parsed[0];

    // Tenta vários caminhos onde o base64 costuma vir
    b64Data = msgStr.base64 || 
              msgStr.message?.documentMessage?.base64 || 
              msgStr.documentMessage?.base64;
  } catch (err) {}
}

// Se o caçador falhar, avisa logo e pára
if (!b64Data) {
  throw new Error('Base64 não encontrado nas informações. Verifica no painel da tua API de WhatsApp se a opção de incluir "base64" no Webhook está mesmo a enviar os dados da imagem/documento.');
}

// ─── 2. CONVERTER BASE64 PARA EXCEL NA RAM ────────────────────────
let buffer;
try {
  // Limpa prefixos do Base64 (ex: data:application/vnd...;base64,)
  let cleanB64 = b64Data.replace(/\s/g, '');
  if (cleanB64.includes(',')) cleanB64 = cleanB64.split(',')[1];

  // Cria o ficheiro real diretamente da string - ADEUS FICHEIROS CORROMPIDOS!
  buffer = Buffer.from(cleanB64, 'base64');

  // Limpeza imediata da string pesada
  b64Data = null; 
  cleanB64 = null;
} catch (err) {
  throw new Error(`Erro ao descodificar o Base64: ${err.message}`);
}

// ─── 3. LER O EXCEL COM SHEETJS ───────────────────────────────────
let workbook;
try {
  workbook = XLSX.read(buffer, { type: 'buffer', cellDates: true });
} catch (err) {
  throw new Error(`Ficheiro corrompido. O Base64 gerado pela API pode estar incompleto: ${err.message}`);
}

buffer = null; // Limpa RAM

if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
  throw new Error('O ficheiro Excel não contém folhas.');
}

// ─── 4. CONVERSÃO INTELIGENTE PARA CSV ────────────────────────────
let conteudoExcel = '';
const resumoFolhas = [];
const MAX_LINHAS_POR_FOLHA = 100; // Previne o estouro de tokens da Mistral

for (const nomeFolha of workbook.SheetNames) {
  const folha = workbook.Sheets[nomeFolha];

  const dados_folha = XLSX.utils.sheet_to_json(folha, {
    header: 1, defval: '', blankrows: false
  });

  if (dados_folha.length === 0) continue;

  const dados_limitados = dados_folha.slice(0, MAX_LINHAS_POR_FOLHA);

  const csv = XLSX.utils.sheet_to_csv(
    XLSX.utils.aoa_to_sheet(dados_limitados), 
    { blankrows: false }
  );

  resumoFolhas.push({
    nome: nomeFolha,
    linhas_totais: dados_folha.length,
    linhas_enviadas: dados_limitados.length
  });

  conteudoExcel += `### Folha: "${nomeFolha}"\n`;
  conteudoExcel += '```csv\n' + csv + '\n```\n\n';
}

workbook = null;

if (!conteudoExcel) throw new Error('Nenhum dado encontrado nas folhas do Excel.');

// ─── 5. CHAMADA À API MISTRAL ─────────────────────────────────────
let analise = '';
try {
  const mistralResp = await axios.post(
    'https://api.mistral.ai/v1/chat/completions',
    {
      model: 'mistral-large-latest',
      messages: [
        { role: 'system', content: 'Responde exclusivamente com a tabela Markdown extraída do CSV. Nada de textos, análises, metadados, linhas de separador, [object Object] ou frases como "aqui estão". Começa logo com | e termina na última linha da tabela.' },
        { role: 'user', content: `Analisa este ficheiro:\n\n${conteudoExcel}` }
      ],
      max_tokens: 4096,
      temperature: 0.1
    },
    {
      headers: { 'Authorization': `Bearer ${API_KEY}`, 'Content-Type': 'application/json' },
      timeout: 90000
    }
  );

  analise = mistralResp.data.choices[0].message.content;
} catch (err) {
  const msg = err.response?.data?.message || err.response?.data?.detail || err.message;
  analise = `[Erro Mistral: ${msg}]`;
}

conteudoExcel = null;

// ─── 6. RETORNO LIMPO (SEGURO PARA N8N) ───────────────────────────
const output = { ...dados };

// Apagamos TUDO o que é pesado para não crashar a UI do n8n
delete output.anexos;
delete output.message_raw;
delete output.base64;

// Injectamos apenas o resultado limpo
output.texto_excel = analise;
output.folhas_excel = resumoFolhas;

return [{ json: output }];

// Dados originais completos (antes do Data Table)
const dadosOriginais = $('Code in JavaScript').first().json;  
// O nó 'Code in JavaScript' já recuperava os dados do 'Calcular Prioridade'

// Dados da tabela (saída do Atualizar Canal Cliente)
const dadosTabela = $json;

// Junta tudo: mantém os originais e adiciona/sobrescreve com os da tabela
const dadosCompletos = {
  ...dadosOriginais,
  ...dadosTabela
};

return { json: dadosCompletos };
